import{_ as n,o as e,c as t,a2 as s}from"./chunks/framework.Wufm-cgV.js";const g=JSON.parse('{"title":"知识库","description":"企业知识管理与 RAG 驱动的上下文注入","frontmatter":{"title":"知识库","description":"企业知识管理与 RAG 驱动的上下文注入"},"headers":[],"relativePath":"zh/guide/knowledge-base.md","filePath":"zh/guide/knowledge-base.md"}'),d={name:"zh/guide/knowledge-base.md"};function l(p,a,o,r,i,c){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="知识库" tabindex="-1">知识库 <a class="header-anchor" href="#知识库" aria-label="Permalink to &quot;知识库&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>WebRouter 的知识库系统捕获、存储和检索组织知识，并自动将相关上下文注入 LLM 请求。它结合了自动对话知识捕获与 RAG（检索增强生成）技术，实现实时上下文注入。</p><h2 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┐     ┌──────────────┐     ┌──────────────┐</span></span>
<span class="line"><span>│  知识捕获      │     │  知识提取      │     │  RAG 注入     │</span></span>
<span class="line"><span>│  (自动)       │     │  (LLM)       │     │  (实时)       │</span></span>
<span class="line"><span>└──────┬───────┘     └──────┬───────┘     └──────┬───────┘</span></span>
<span class="line"><span>       │                    │                    │</span></span>
<span class="line"><span>       ▼                    ▼                    ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  wr_knowledge_raw                     │</span></span>
<span class="line"><span>│  从对话中捕获的原始对话片段                               │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                       │ LLM 提取</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  wr_agent_memory                      │</span></span>
<span class="line"><span>│  从原始数据提取的结构化事实和偏好                           │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                       │ 向量嵌入</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  wr_knowledge_vectors                 │</span></span>
<span class="line"><span>│  用于语义搜索的向量嵌入                                  │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>               RAG 上下文注入</span></span>
<span class="line"><span>           （注入到 system prompt）</span></span></code></pre></div><h2 id="核心组件" tabindex="-1">核心组件 <a class="header-anchor" href="#核心组件" aria-label="Permalink to &quot;核心组件&quot;">​</a></h2><h3 id="_1-知识捕获-自动" tabindex="-1">1. 知识捕获（自动） <a class="header-anchor" href="#_1-知识捕获-自动" aria-label="Permalink to &quot;1. 知识捕获（自动）&quot;">​</a></h3><p>当 Token 启用了 <code>KnowledgeCaptureEnabled</code>，每轮对话自动捕获：</p><ul><li><strong>非流式</strong>：完整请求/响应对在完成后保存</li><li><strong>流式</strong>：累积内容在流结束后保存</li><li>内容存储在 <code>wr_knowledge_raw</code> 中供后续提取</li></ul><p>在 <strong>令牌管理</strong> → <strong>知识捕获</strong> 中按 Token 启用。</p><h3 id="_2-知识提取-llm-驱动" tabindex="-1">2. 知识提取（LLM 驱动） <a class="header-anchor" href="#_2-知识提取-llm-驱动" aria-label="Permalink to &quot;2. 知识提取（LLM 驱动）&quot;">​</a></h3><p>捕获的原始对话由 LLM 处理，提取结构化知识：</p><ul><li>事实、偏好、决策和流程</li><li>存储为 <code>wr_agent_memory</code> 中的结构化条目</li><li>支持批量提取和增量处理</li></ul><p>触发提取：</p><ul><li><strong>管理面板</strong>：知识库 → 提取</li><li><strong>API</strong>：<code>POST /admin/knowledge_extract</code></li></ul><h3 id="_3-rag-注入-实时" tabindex="-1">3. RAG 注入（实时） <a class="header-anchor" href="#_3-rag-注入-实时" aria-label="Permalink to &quot;3. RAG 注入（实时）&quot;">​</a></h3><p>每次请求前，若 Token 启用了 RAG：</p><ol><li>从请求中提取用户查询</li><li>向量化并搜索 <code>wr_knowledge_vectors</code></li><li>检索 Top-K 相关片段</li><li>将匹配的上下文注入 system prompt</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System: 你是一个有用的助手。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[知识库上下文]</span></span>
<span class="line"><span>来自知识库的相关信息：</span></span>
<span class="line"><span>- 事实 1：...</span></span>
<span class="line"><span>- 事实 2：...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: 我们的部署流程是什么？</span></span></code></pre></div><h2 id="token-配置项" tabindex="-1">Token 配置项 <a class="header-anchor" href="#token-配置项" aria-label="Permalink to &quot;Token 配置项&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设置项</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>rag_enabled</code></td><td>false</td><td>启用 RAG 上下文注入</td></tr><tr><td><code>rag_top_k</code></td><td>3</td><td>检索片段数量</td></tr><tr><td><code>rag_min_relevance</code></td><td>0.7</td><td>最低相似度阈值</td></tr><tr><td><code>rag_hybrid_alpha</code></td><td>0</td><td>混合搜索权重（0 = 纯向量，&gt;0 = BM25 + 向量）</td></tr><tr><td><code>rag_reranker</code></td><td>none</td><td>结果重排序模型</td></tr><tr><td><code>system_prompt_knowledge</code></td><td>&quot;&quot;</td><td>始终注入的静态知识</td></tr><tr><td><code>knowledge_department</code></td><td>&quot;&quot;</td><td>部门过滤，限定搜索范围</td></tr><tr><td><code>knowledge_capture_enabled</code></td><td>false</td><td>自动捕获对话</td></tr></tbody></table><h2 id="分块策略" tabindex="-1">分块策略 <a class="header-anchor" href="#分块策略" aria-label="Permalink to &quot;分块策略&quot;">​</a></h2><p>文档在嵌入前按可配置策略分块：</p><table tabindex="0"><thead><tr><th>策略</th><th>说明</th></tr></thead><tbody><tr><td><code>fixed</code></td><td>按固定字符数切分，带重叠</td></tr><tr><td><code>sentence</code></td><td>按句子边界切分</td></tr><tr><td><code>paragraph</code></td><td>按段落边界切分</td></tr></tbody></table><h2 id="混合搜索" tabindex="-1">混合搜索 <a class="header-anchor" href="#混合搜索" aria-label="Permalink to &quot;混合搜索&quot;">​</a></h2><p>当 <code>rag_hybrid_alpha &gt; 0</code> 时，wr-proxy 结合：</p><ul><li><strong>向量搜索</strong> — 通过嵌入进行语义相似度匹配</li><li><strong>BM25 关键词搜索</strong> — 精确词项匹配</li></ul><p>alpha 参数控制混合比例（0 = 纯向量，1 = 纯 BM25）。</p><h2 id="部门范围" tabindex="-1">部门范围 <a class="header-anchor" href="#部门范围" aria-label="Permalink to &quot;部门范围&quot;">​</a></h2><p>为多团队部署组织知识：</p><ol><li>为每个 Token 设置 <code>knowledge_department</code>（如 &quot;engineering&quot;、&quot;marketing&quot;）</li><li>RAG 搜索范围限定在 Token 所属部门</li><li>部门搜索结果为空时，回退到全局搜索</li></ol><h2 id="管理端点" tabindex="-1">管理端点 <a class="header-anchor" href="#管理端点" aria-label="Permalink to &quot;管理端点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端点</th><th>说明</th></tr></thead><tbody><tr><td><code>GET /admin/knowledge_stats</code></td><td>知识库统计</td></tr><tr><td><code>POST /admin/knowledge_analyze</code></td><td>分析知识质量</td></tr><tr><td><code>POST /admin/knowledge_extract</code></td><td>触发 LLM 提取</td></tr><tr><td><code>POST /admin/knowledge_embedding_backfill</code></td><td>回填向量嵌入</td></tr><tr><td><code>GET /admin/knowledge_rag_stats</code></td><td>RAG 命中/未命中统计</td></tr><tr><td><code>GET /admin/knowledge_prompt_preview</code></td><td>预览注入的 prompt</td></tr></tbody></table>`,33)])])}const _=n(d,[["render",l]]);export{g as __pageData,_ as default};
